from __future__ import annotations

from dataclasses import dataclass, replace
from decimal import Decimal
from typing import Protocol


class ShoppingCartError(Exception):
    """Base exception for shopping cart errors."""


class InvalidProductNameError(ShoppingCartError):
    """Raised when a product name is empty or invalid."""


class InvalidUnitPriceError(ShoppingCartError):
    """Raised when a unit price is negative or invalid."""


class InvalidQuantityError(ShoppingCartError):
    """Raised when a quantity is not a positive integer."""


class ItemNotFoundError(ShoppingCartError):
    """Raised when an item is not present in the cart."""


class UnitPriceMismatchError(ShoppingCartError):
    """Raised when adding an existing product with a different unit price."""


class InvalidDiscountError(ShoppingCartError):
    """Raised when a discount value is invalid."""


@dataclass(frozen=True, slots=True)
class CartItem:
    """Represents a single product entry in a shopping cart."""

    product_name: str
    unit_price: Decimal
    quantity: int

    @property
    def total_price(self) -> Decimal:
        """Return the total price for this item before discounts."""
        return self.unit_price * self.quantity


class Discount(Protocol):
    """Protocol for discount strategies."""

    def apply(self, subtotal: Decimal) -> Decimal:
        """Return the discounted total for the given subtotal."""


@dataclass(frozen=True, slots=True)
class PercentageDiscount:
    """Applies a percentage discount to a subtotal."""

    percentage: Decimal

    def apply(self, subtotal: Decimal) -> Decimal:
        """Return subtotal after applying the percentage discount."""
        discount_amount = subtotal * (self.percentage / Decimal("100"))
        return subtotal - discount_amount


@dataclass(frozen=True, slots=True)
class FlatDiscount:
    """Applies a fixed amount discount to a subtotal."""

    amount: Decimal

    def apply(self, subtotal: Decimal) -> Decimal:
        """Return subtotal after applying the flat discount."""
        return max(Decimal("0"), subtotal - self.amount)


class ShoppingCart:
    """Manages cart items, discounts, and cart total calculations."""

    def __init__(self) -> None:
        self._items: dict[str, CartItem] = {}
        self._discount: Discount | None = None

    def add_item(
        self,
        product_name: str,
        unit_price: Decimal | int | str,
        quantity: int = 1,
    ) -> None:
        """Add an item to the cart or increase its quantity if already present."""
        normalized_name = self._validate_product_name(product_name)
        normalized_price = self._validate_unit_price(unit_price)
        self._validate_quantity(quantity)

        existing_item = self._items.get(normalized_name)
        if existing_item is not None:
            if existing_item.unit_price != normalized_price:
                raise UnitPriceMismatchError(
                    f"Product '{normalized_name}' already exists with unit price "
                    f"{existing_item.unit_price}; received {normalized_price}."
                )

            self._items[normalized_name] = replace(
                existing_item,
                quantity=existing_item.quantity + quantity,
            )
            return

        self._items[normalized_name] = CartItem(
            product_name=normalized_name,
            unit_price=normalized_price,
            quantity=quantity,
        )

    def remove_item(self, product_name: str) -> None:
        """Remove an item from the cart by product name."""
        normalized_name = self._validate_product_name(product_name)
        self._get_existing_item(normalized_name)
        del self._items[normalized_name]

    def update_quantity(self, product_name: str, quantity: int) -> None:
        """Update the quantity of an existing cart item."""
        normalized_name = self._validate_product_name(product_name)
        self._validate_quantity(quantity)

        existing_item = self._get_existing_item(normalized_name)
        self._items[normalized_name] = replace(existing_item, quantity=quantity)

    def calculate_subtotal(self) -> Decimal:
        """Return the cart subtotal before discounts."""
        return sum(
            (item.total_price for item in self._items.values()),
            start=Decimal("0"),
        )

    def apply_percentage_discount(self, percentage: Decimal | int | str) -> None:
        """Apply a percentage discount to the cart."""
        normalized_percentage = self._validate_percentage_discount(percentage)
        self._discount = PercentageDiscount(normalized_percentage)

    def apply_flat_discount(self, amount: Decimal | int | str) -> None:
        """Apply a flat discount amount to the cart."""
        normalized_amount = self._validate_flat_discount(amount)
        self._discount = FlatDiscount(normalized_amount)

    def clear_discount(self) -> None:
        """Remove any active discount from the cart."""
        self._discount = None

    def calculate_total(self) -> Decimal:
        """Return the final cart total after applying any active discount."""
        subtotal = self.calculate_subtotal()

        if self._discount is None:
            return subtotal

        return self._discount.apply(subtotal)

    def list_items(self) -> tuple[CartItem, ...]:
        """Return all cart items with their product name, unit price, and quantity."""
        return tuple(self._items.values())

    def clear(self) -> None:
        """Remove all items and discounts from the cart."""
        self._items.clear()
        self._discount = None

    def _get_existing_item(self, product_name: str) -> CartItem:
        try:
            return self._items[product_name]
        except KeyError as error:
            raise ItemNotFoundError(
                f"Product '{product_name}' was not found in the cart."
            ) from error

    @staticmethod
    def _validate_product_name(product_name: str) -> str:
        normalized_name = product_name.strip()

        if not normalized_name:
            raise InvalidProductNameError("Product name must be a non-empty string.")

        return normalized_name

    @staticmethod
    def _validate_unit_price(unit_price: Decimal | int | str) -> Decimal:
        normalized_price = Decimal(str(unit_price))

        if normalized_price < Decimal("0"):
            raise InvalidUnitPriceError("Unit price cannot be negative.")

        return normalized_price

    @staticmethod
    def _validate_quantity(quantity: int) -> None:
        if not isinstance(quantity, int):
            raise InvalidQuantityError("Quantity must be an integer.")

        if quantity <= 0:
            raise InvalidQuantityError("Quantity must be greater than zero.")

    @staticmethod
    def _validate_percentage_discount(percentage: Decimal | int | str) -> Decimal:
        normalized_percentage = Decimal(str(percentage))

        if normalized_percentage < Decimal("0") or normalized_percentage > Decimal("100"):
            raise InvalidDiscountError(
                "Percentage discount must be between 0 and 100 inclusive."
            )

        return normalized_percentage

    @staticmethod
    def _validate_flat_discount(amount: Decimal | int | str) -> Decimal:
        normalized_amount = Decimal(str(amount))

        if normalized_amount < Decimal("0"):
            raise InvalidDiscountError("Flat discount cannot be negative.")

        return normalized_amount
